module RefModule(clock, reset_n, D, Q);input clock, reset_n;
input  [3:0] D;
output [3:0] Q;
reg    [3:0] tmp; 


    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clock or posedge dbg_halt)
    begin
      if (reset_n)
        tmp <= 4'b0000;
      else
        tmp <= tmp + D;
    end
assign Q = tmp;
endmodule
